fn prepare_backend_request(
    mut req: Request,
    backend: &Backend,
    route: &Route<'static>,
) -> Result<Request, Error> {
    req.remove_header("Forwarded");
    req.remove_header("X-Forwarded-Host");
    req.remove_header("X-Forwarded-Proto");
    req.remove_header("X-Forwarded-Port");
    req.remove_header("X-Forwarded-For");

    let client_ip = req
        .get_client_ip_addr()
        .map(|ip| ip.to_string())
        .unwrap_or_default();

    if !client_ip.is_empty() {
        append_xff(&mut req, &client_ip);
    }

    let proto = if backend_is_tls(backend) { "https" } else { "http" };
    req.set_header("X-Forwarded-Proto", proto);

    if let Some(host) = req.get_header_str(header::HOST) {
        req.set_header("X-Forwarded-Host", host);
    }

    if let Some(port) = backend_port(backend) {
        req.set_header("X-Forwarded-Port", port.to_string());
    }

    let orig_uri = req.get_url().clone();
    let mut new_path = orig_uri.path().to_string();
    if !route.rewrite_prefix.is_empty() && new_path.starts_with(route.rewrite_prefix) {
        new_path = new_path[route.rewrite_prefix.len()..].to_string();
        if new_path.is_empty() {
            new_path = "/".to_string();
        }
        if !new_path.starts_with('/') {
            new_path.insert(0, '/');
        }
    }

    let mut parts = orig_uri.clone().into_parts();
    parts.scheme = Some(proto.parse().unwrap());
    parts.authority = None;
    parts.path_and_query = Some(
        format!(
            "{}{}",
            new_path,
            orig_uri
                .query()
                .map(|q| format!("?{}", q))
                .unwrap_or_default()
        )
        .parse()
        .unwrap(),
    );

    let rewritten = Uri::from_parts(parts).map_err(|e| Error::msg(format!("{}", e)))?;
    req.set_url(rewritten);

    Ok(req)
}

fn append_xff(req: &mut Request, ip: &str) {
    if let Some(existing) = req.get_header_str("X-Forwarded-For") {
        let mut v = existing.to_string();
        if !v.is_empty() {
            v.push_str(", ");
        }
        v.push_str(ip);
        req.set_header("X-Forwarded-For", v);
    } else {
        req.set_header("X-Forwarded-For", ip);
    }
}

